client_script:
frappe.web_form.after_load = () => {
    if (window.location.pathname.endsWith("/new") && frappe.session.user) {
        let current_path = window.location.href;
        window.location.href = current_path.replace("/new", "/" + frappe.session.user);
    }
}

frappe.ready(function () {
    document.title = "Kenya Red Cross Society Internship Application";
});

custom_css:
/* Kenya Red Cross Theme */

.web-form-container {
    max-width: 950px;
    margin: auto;
    border-radius: 12px;
    background: #ffffff;
    padding: 25px;
    box-shadow: 0 6px 20px rgba(0,0,0,0.12);
}

.page-head,
.web-form-header {
    background: #d71920;
    color: white;
    padding: 20px;
    border-radius: 12px 12px 0 0;
}

.btn-primary {
    background: #d71920 !important;
    border-color: #d71920 !important;
}

.btn-primary:hover {
    background: #b51218 !important;
    border-color: #b51218 !important;
}

label {
    font-weight: 600;
    color: #444;
}

.form-control:focus {
    border-color: #d71920;
    box-shadow: 0 0 0 0.2rem rgba(215,25,32,0.2);
}

.section-head {
    color: #d71920;
    font-weight: bold;
    border-bottom: 2px solid #d71920;
    margin-bottom: 15px;
    padding-bottom: 5px;
}
